package agti

import (
	"encoding/json"
	"os"
	"testing"
)

// Golden cases generated by running the original demo JS engine
// (activities/agent-rapport/demo/lib/engine.js in the EigenfluxWeb repo) over
// deterministic answer patterns. The Go port must reproduce every output
// exactly — see the note at the top of engine.go.
type goldenFile struct {
	Cases []goldenCase `json:"cases"`
}

type goldenCase struct {
	Name        string            `json:"name"`
	QuestionIDs []string          `json:"questionIds"`
	Agent       map[string]string `json:"agent"`
	Human       map[string]string `json:"human"`
	Expected    goldenExpected    `json:"expected"`
}

type goldenExpected struct {
	Code          string `json:"code"`
	Match         int    `json:"match"`
	Total         int    `json:"total"`
	EnergyBias    int    `json:"energyBias"`
	PoliteGap     int    `json:"politeGap"`
	PolarOpposite int    `json:"polarOpposite"`
	HumanRarity   int    `json:"humanRarity"`
	KeyMiss       bool   `json:"keyMiss"`
	AgentView     string `json:"agentView"`
	SweetID       string `json:"sweetId"`
	WorstID       string `json:"worstId"`
}

func loadTestBank(t *testing.T) *Bank {
	t.Helper()
	b, err := LoadBank("../../static/agti")
	if err != nil {
		t.Fatalf("load bank: %v", err)
	}
	return b
}

func TestAnalyzeGolden(t *testing.T) {
	bank := loadTestBank(t)
	data, err := os.ReadFile("testdata/golden.json")
	if err != nil {
		t.Fatalf("read golden: %v", err)
	}
	var gf goldenFile
	if err := json.Unmarshal(data, &gf); err != nil {
		t.Fatalf("parse golden: %v", err)
	}
	if len(gf.Cases) == 0 {
		t.Fatal("no golden cases")
	}
	codes := map[string]bool{}
	for _, tc := range gf.Cases {
		questions := make([]Question, 0, len(tc.QuestionIDs))
		for _, id := range tc.QuestionIDs {
			q := bank.Get(id)
			if q == nil {
				t.Fatalf("%s: question %s not in bank", tc.Name, id)
			}
			questions = append(questions, *q)
		}
		a := Analyze(questions, tc.Agent, tc.Human)
		e := tc.Expected
		codes[a.Code] = true
		if a.Code != e.Code || a.Match != e.Match || a.Total != e.Total ||
			a.EnergyBias != e.EnergyBias || a.PoliteGap != e.PoliteGap ||
			a.PolarOpposite != e.PolarOpposite || a.HumanRarity != e.HumanRarity ||
			a.KeyMiss != e.KeyMiss {
			t.Errorf("%s: signals mismatch\n got  code=%s match=%d total=%d bias=%d polite=%d polar=%d rarity=%d keyMiss=%v\n want code=%s match=%d total=%d bias=%d polite=%d polar=%d rarity=%d keyMiss=%v",
				tc.Name, a.Code, a.Match, a.Total, a.EnergyBias, a.PoliteGap, a.PolarOpposite, a.HumanRarity, a.KeyMiss,
				e.Code, e.Match, e.Total, e.EnergyBias, e.PoliteGap, e.PolarOpposite, e.HumanRarity, e.KeyMiss)
		}
		if a.AgentView != e.AgentView {
			t.Errorf("%s: agentView mismatch\n got  %q\n want %q", tc.Name, a.AgentView, e.AgentView)
		}
		sweetID := ""
		if a.Sweet != nil {
			sweetID = a.Sweet.ID
		}
		worstID := ""
		if a.Worst != nil {
			worstID = a.Worst.ID
		}
		if sweetID != e.SweetID || worstID != e.WorstID {
			t.Errorf("%s: sweet/worst mismatch: got (%s, %s), want (%s, %s)", tc.Name, sweetID, worstID, e.SweetID, e.WorstID)
		}
	}
	// All 10 types must be exercised so every cascade branch is covered.
	for _, c := range []string{"SOUL", "GANG", "XRAY", "NPC", "KISS", "CTRL", "RIDDLE", "VS", "MAMA", "FAKE"} {
		if !codes[c] {
			t.Errorf("golden cases never produced type %s", c)
		}
	}
}

func TestNormalizeAnswers(t *testing.T) {
	bank := loadTestBank(t)
	qs := bank.Items[:3]
	got := NormalizeAnswers(qs, map[string]string{
		qs[0].ID: qs[0].Options[1].Key, // valid → kept
		qs[1].ID: "Z",                  // invalid → first option
		// qs[2] missing → first option
	})
	if got[qs[0].ID] != qs[0].Options[1].Key {
		t.Errorf("valid answer overwritten: %v", got[qs[0].ID])
	}
	if got[qs[1].ID] != qs[1].Options[0].Key {
		t.Errorf("invalid answer not normalized: %v", got[qs[1].ID])
	}
	if got[qs[2].ID] != qs[2].Options[0].Key {
		t.Errorf("missing answer not normalized: %v", got[qs[2].ID])
	}
}

func TestBankPick(t *testing.T) {
	bank := loadTestBank(t)
	qs := bank.Pick()
	if len(qs) != bank.PickCount {
		t.Fatalf("pick returned %d questions, want %d", len(qs), bank.PickCount)
	}
	seen := map[string]bool{}
	for _, q := range qs {
		if seen[q.ID] {
			t.Fatalf("duplicate question %s in pick", q.ID)
		}
		seen[q.ID] = true
		if len(q.Options) < 2 {
			t.Fatalf("question %s has %d options", q.ID, len(q.Options))
		}
	}
}
